package com.juanma0511.rootdetector.detector

import java.util.Base64

object HardcodedSignals {
    private const val KEY: Int = 0x37

    private fun decode(blob: String): String {
        val decoded = Base64.getDecoder().decode(blob)
        return String(CharArray(decoded.size) { index -> (decoded[index].toInt() xor KEY).toChar() })
    }

    private fun decodeLines(blob: String): List<String> = decode(blob).split("\n").filter { it.isNotEmpty() }

    private fun decodeMap(blob: String): Map<String, String> = decodeLines(blob).associate {
        val idx = it.indexOf("\t")
        if (idx == -1) it to "" else it.substring(0, idx) to it.substring(idx + 1)
    }

